import{_ as u,c as f,o as r,b as a,j as _,a as t,w as e,d as o,u as c,p as d}from"./index-DBUtkoex.js";const p={class:"about-container"},h={class:"container"},m={class:"about-carousel"},b={class:"carousel-item"},g={class:"image-slot"},w={class:"carousel-item"},x={class:"image-slot"},j={class:"carousel-item"},V={class:"image-slot"},y={__name:"AboutView",setup(A){return(B,s)=>{const i=o("el-icon"),n=o("el-image"),l=o("el-carousel-item"),v=o("el-carousel");return r(),f("div",p,[a("div",h,[s[3]||(s[3]=a("h2",null,"学校简介",-1)),a("div",m,[t(v,{interval:3e3,type:"card",height:"400px",arrow:"hover"},{default:e(()=>[t(l,null,{default:e(()=>[a("div",b,[t(n,{src:"/images/zhixiaodamen.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:e(()=>[a("div",g,[t(i,null,{default:e(()=>[t(c(d))]),_:1}),s[0]||(s[0]=a("span",null,"学校环境图片",-1))])]),_:1})])]),_:1}),t(l,null,{default:e(()=>[a("div",w,[t(n,{src:"/images/shixunlou.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:e(()=>[a("div",x,[t(i,null,{default:e(()=>[t(c(d))]),_:1}),s[1]||(s[1]=a("span",null,"实训设备图片",-1))])]),_:1})])]),_:1}),t(l,null,{default:e(()=>[a("div",j,[t(n,{src:"/images/diannaojifang.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:e(()=>[a("div",V,[t(i,null,{default:e(()=>[t(c(d))]),_:1}),s[2]||(s[2]=a("span",null,"培训课堂图片",-1))])]),_:1})])]),_:1})]),_:1})]),s[4]||(s[4]=_('<div class="full-intro" data-v-1185f314><section class="about-section" data-v-1185f314><h3 data-v-1185f314>学校概况</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>枝江三宁职业技术学校（以下简称三宁职校）系政府人力资源与社会保障部门批准设立，湖北三宁化工股份有限公司投资建设的培训学校，学校创办于2013年4月，位于枝江市马家店前进路17号。</p></div></section><section class="about-section" data-v-1185f314><h3 data-v-1185f314>资质认证</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>三宁职校系湖北省安全生产教育培训机构、湖北省特种设备作业人员考试点，枝江化工安全技能实训基地、全国大学生实训实习基地、宜昌市产业工人培训基地，2023年1月被授予全国首批石油和化工行业安全技能实训基地。</p></div></section><section class="about-section" data-v-1185f314><h3 data-v-1185f314>硬件设施</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>三宁职校占地50余亩，建筑面积31190平米，学校设置教学楼、实训大楼、办公楼、公寓住宿楼、食堂、运动场等功能分区，布局合理；建有化工工艺、机械维修、高低压电工、化工仪表自动化、金属焊接与热切割、特殊作业、安全防护和体验装置等10多个专业实训室和训练场所；拥有多媒体、OTS仿真、智慧屏等先进教学设施；学校运动场、文体健身设施、无线网络，宿舍空调、热水供应等配套设施一应俱全。</p></div></section><section class="about-section" data-v-1185f314><h3 data-v-1185f314>培训项目</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>三宁职校常年开设单位负责人、安全管理人员、电工、焊工、高处、危化等特种作业人员取证与复审培训班；开展锅炉、水处理、压力容器等特种设备操作员培训考试，开展消防值班员培训。同时为企业新入职人员、在岗员工开展钳工、电工、仪表工、焊工、化工操作工的技能提升培训和等级认定，还常年开设内训师、数字化工具应用、AI应用、Office办公技能提升等公共课程，为广大职场人职业技能提升保驾护航。</p></div></section><section class="about-section" data-v-1185f314><h3 data-v-1185f314>技能大赛</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>三宁职校被授予技能大赛实训基地，多次承办省市级叉车、化工总控工、仪器仪表工、电工、钳工、化学检验工技能大赛，并得到各级主办单位的高度评价。</p></div></section><section class="about-section" data-v-1185f314><h3 data-v-1185f314>发展规划</h3><div class="about-content" data-v-1185f314><p data-v-1185f314>三宁职校以赋能三宁公司和姚家港化工园区员工为主业，本着立足宜昌，辐射湖北的思路，积极对外拓展培训与相关业务。近年来为宜昌市东部产业新区、孝感东城和盐化工业园、潜江工业园、荆州松滋工业园等园区和机构提供了多工种的安全培训、专业技能提升和取证服务。未来，三宁职校将致力于打造湖北一流、行业知名、化工专业特色显著的培训学校，为化工行业发展和地方经济建设做出更大的贡献。</p></div></section></div>',1))])])}}},k=u(y,[["__scopeId","data-v-1185f314"]]);export{k as default};
